    23→import { TabBar, KanbanBoard, LogPanel, TerminalPanel, ProjectSelector, ProgressCard, Settings, TaskModal, TaskExecutionModal } from './components';
    24→import type { HQSettings, TaskData } from './components';
    25→import type { LogEntry } from './components';
