    32→
    33→// Process info for log panel
    34→interface ProcessInfo {
    35→  id: string;
    36→  name: string;
    37→}
    38→
    39→// Initialize harness database if it doesn't exist
    40→async function initializeHarnessIfNeeded(projectPath: string): Promise<boolean> {
    41→  try {
    42→    // Try to run status command - if it fails, db doesn't exist
    43→    await runHarnessCommand(projectPath, ['db', 'status']);
    44→    return true; // Already initialized
    45→  } catch {
    46→    // Database doesn't exist, initialize it
    47→    try {
    48→      await runHarnessCommand(projectPath, ['init']);
    49→      console.log('Harness database initialized for:', projectPath);
    50→      return true;
    51→    } catch (initError) {
    52→      console.error('Failed to initialize harness:', initError);
    53→      return false;
    54→    }
    55→  }
    56→}
    57→
    58→// Fetch tasks from harness CLI and convert to Feature format
    59→async function fetchProjectFeatures(projectPath: string): Promise<Feature[]> {
    60→  try {
    61→    const result = await runHarnessCommand(projectPath, ['task', 'list', '--format', 'json']);
    62→
    63→    const response = JSON.parse(result);
    64→    // CLI returns paginated response: { items: [...], has_next, has_prev, ... }
    65→    const tasks = response.items || response;
    66→    if (!Array.isArray(tasks)) return [];
    67→
    68→    return tasks.map((task: {
    69→      id: string;
    70→      title: string;
    71→      description?: string;
    72→      status: string;
    73→      category?: string;
    74→      is_passed?: boolean;
    75→    }) => ({
    76→      id: task.id,
    77→      description: task.title,
    78→      category: task.category || 'general',
    79→      priority: 'medium',
    80→      status: task.status.toLowerCase(),
    81→      passes: task.is_passed || task.status.toLowerCase() === 'done',
    82→      steps: task.description ? [task.description] : [],
    83→    }));
    84→  } catch (error) {
    85→    console.error('Failed to fetch project features:', error);
    86→    return [];
    87→  }
    88→}
    89→
    90→function App() {
    91→  // Backend connection state
    92→  const [isConnected, setIsConnected] = useState(false);
    93→  const [connectionError, setConnectionError] = useState<string | null>(null);
    94→
    95→  // Project state - start empty, no mock projects
    96→  const [projects, setProjects] = useState<Project[]>([]);
    97→  const [activeProjectId, setActiveProjectId] = useState<string | null>(null);
    98→
    99→  // Features state - fetched from harness CLI
   100→  const [features, setFeatures] = useState<Feature[]>([]);
   101→  const [isLoadingFeatures, setIsLoadingFeatures] = useState(false);
   102→
   103→  // Project selector dialog state
   104→  const [isProjectSelectorOpen, setIsProjectSelectorOpen] = useState(false);
   105→
   106→  // Settings dialog state
   107→  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
   108→  const [settings, setSettings] = useState<HQSettings>({
   109→    theme: 'system',
   110→    logBufferSize: 10000,
   111→    defaultShell: '/bin/zsh',
   112→    ptyRows: 24,
   113→    ptyCols: 80,
   114→    autoScrollLogs: true,
   115→    showTimestamps: true,
   116→  });
   117→
   118→  // Log state - starts empty, filled by PTY events
   119→  const [logs, setLogs] = useState<LogEntry[]>([]);
   120→  const [processes, setProcesses] = useState<ProcessInfo[]>([]);
   121→
   122→  // Task modal state
   123→  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
   124→  const [editingTask, setEditingTask] = useState<Feature | undefined>(undefined);
   125→
   126→  // Task execution modal state
   127→  const [isExecutionModalOpen, setIsExecutionModalOpen] = useState(false);
   128→  const [executingTask, setExecutingTask] = useState<Feature | null>(null);
   129→
   130→  // Check backend connection on mount
   131→  useEffect(() => {
   132→    const checkConnection = async () => {
   133→      const available = await isBackendAvailable();
   134→      setIsConnected(available);
   135→      if (!available) {
   136→        setConnectionError('Backend server not available. Please start the server with: bun run server/index.ts');
   137→      } else {
   138→        setConnectionError(null);
   139→      }
   140→    };
   141→
   142→    checkConnection();
   143→    // Check every 5 seconds
   144→    const interval = setInterval(checkConnection, 5000);
   145→    return () => clearInterval(interval);
   146→  }, []);
   147→
   148→  // Open project selector on first launch if no projects
   149→  useEffect(() => {
   150→    if (projects.length === 0 && isConnected) {
   151→      setIsProjectSelectorOpen(true);
   152→    }
   153→  }, [isConnected]);
   154→
   155→  // Fetch features when active project changes (initialize harness if needed)
   156→  useEffect(() => {
   157→    const activeProject = projects.find(p => p.id === activeProjectId);
   158→    if (activeProject && isConnected) {
   159→      setIsLoadingFeatures(true);
   160→      // First ensure harness is initialized, then fetch features
   161→      initializeHarnessIfNeeded(activeProject.path)
   162→        .then((initialized) => {
   163→          if (initialized) {
   164→            return fetchProjectFeatures(activeProject.path);
   165→          }
   166→          return [];
   167→        })
   168→        .then(setFeatures)
   169→        .finally(() => setIsLoadingFeatures(false));
   170→    } else {
   171→      setFeatures([]);
   172→    }
   173→  }, [activeProjectId, projects, isConnected]);
   174→
   175→  // Listen for PTY output events to populate logs
   176→  useEffect(() => {
   177→    if (!isConnected) return;
   178→
   179→    let unlistenFn: (() => void) | null = null;
   180→
   181→    const setupListener = async () => {
   182→      try {
   183→        unlistenFn = await onPtyOutput((payload) => {
   184→          const { id, data } = payload;
   185→
   186→          // Add process if not already tracked
   187→          setProcesses(prev => {
   188→            if (!prev.find(p => p.id === id)) {
   189→              return [...prev, { id, name: `Process ${id.slice(0, 8)}` }];
   190→            }
   191→            return prev;
   192→          });
   193→
   194→          // Add log entry
   195→          setLogs(prev => {
   196→            const newLogs = [...prev, {
   197→              timestamp: Date.now(),
   198→              processId: id,
   199→              processName: `Process ${id.slice(0, 8)}`,
   200→              message: data,
   201→              level: 'info' as const,
   202→            }];
   203→            // Keep only last N logs based on settings
   204→            return newLogs.slice(-settings.logBufferSize);
   205→          });
   206→        });
   207→      } catch (err) {
   208→        console.error('Failed to setup PTY listener:', err);
   209→      }
   210→    };
   211→
   212→    setupListener();
   213→
   214→    return () => {
   215→      if (unlistenFn) {
   216→        unlistenFn();
   217→      }
   218→    };
   219→  }, [isConnected, settings.logBufferSize]);
   220→
   221→  const handleClearLogs = useCallback(() => {
   222→    setLogs([]);
   223→  }, []);
   224→
   225→  // Tab handlers
   226→  const handleSelectProject = useCallback((projectId: string) => {
   227→    setActiveProjectId(projectId);
   228→  }, []);
   229→
   230→  const handleCloseProject = useCallback((projectId: string) => {
   231→    setProjects((prev) => {
   232→      const filtered = prev.filter((p) => p.id !== projectId);
   233→      // If closing active tab, switch to previous or next
   234→      if (activeProjectId === projectId && filtered.length > 0) {
   235→        const idx = prev.findIndex((p) => p.id === projectId);
   236→        const newActive = filtered[Math.max(0, idx - 1)];
   237→        setActiveProjectId(newActive.id);
   238→      } else if (filtered.length === 0) {
   239→        setActiveProjectId(null);
   240→      }
   241→      return filtered;
   242→    });
   243→  }, [activeProjectId]);
   244→
   245→  const handleAddProject = useCallback(() => {
   246→    setIsProjectSelectorOpen(true);
   247→  }, []);
   248→
   249→  // Handle selecting a project from the project selector
   250→  const handleSelectProjectFromDialog = useCallback((path: string, name: string) => {
   251→    // Check if project is already open
   252→    const existing = projects.find(p => p.path === path);
   253→    if (existing) {
   254→      setActiveProjectId(existing.id);
   255→      return;
   256→    }
   257→
   258→    const id = `proj-${Date.now()}`;
   259→    const newProject: Project = {
   260→      id,
   261→      path,
   262→      name,
   263→      harness: {
   264→        progressFile: '.harness/progress.txt',
   265→        featuresFile: '.harness/features.json',
   266→      },
   267→    };
   268→    setProjects((prev) => [...prev, newProject]);
   269→    setActiveProjectId(id);
   270→  }, [projects]);
   271→
   272→  const handleReorderProjects = useCallback((order: string[]) => {
   273→    setProjects((prev) => {
   274→      const projectMap = new Map(prev.map((p) => [p.id, p]));
   275→      return order.map((id) => projectMap.get(id)).filter(Boolean) as Project[];
   276→    });
   277→  }, []);
   278→
   279→  // Refresh features for active project
   280→  const handleRefreshFeatures = useCallback(() => {
   281→    const activeProject = projects.find(p => p.id === activeProjectId);
   282→    if (activeProject && isConnected) {
   283→      setIsLoadingFeatures(true);
   284→      fetchProjectFeatures(activeProject.path)
   285→        .then(setFeatures)
   286→        .finally(() => setIsLoadingFeatures(false));
   287→    }
   288→  }, [activeProjectId, projects, isConnected]);
   289→
   290→  // Task CRUD handlers
   291→  const handleOpenAddTask = useCallback(() => {
   292→    setEditingTask(undefined);
   293→    setIsTaskModalOpen(true);
   294→  }, []);
   295→
   296→  const handleOpenEditTask = useCallback((task: Feature) => {
   297→    setEditingTask(task);
   298→    setIsTaskModalOpen(true);
   299→  }, []);
   300→
   301→  const handleCloseTaskModal = useCallback(() => {
   302→    setIsTaskModalOpen(false);
   303→    setEditingTask(undefined);
   304→  }, []);
   305→
   306→  const handleSaveTask = useCallback(async (taskData: TaskData, taskId?: string) => {
   307→    const activeProject = projects.find(p => p.id === activeProjectId);
   308→    if (!activeProject) {
   309→      throw new Error('No active project selected');
   310→    }
   311→
   312→    const args = taskId
   313→      ? ['task', 'update', taskId]
   314→      : ['task', 'add', taskData.title];
   315→
   316→    // Add flags for update or creation
   317→    if (taskId) {
   318→      args.push('--title', taskData.title);
   319→    }
   320→    if (taskData.description) {
   321→      args.push('--description', taskData.description);
   322→    }
   323→    args.push('--status', taskData.status.toLowerCase());
   324→    if (taskData.category) {
   325→      args.push('--category', taskData.category);
   326→    }
   327→
   328→    try {
   329→      await runHarnessCommand(activeProject.path, args);
   330→      // Refresh the task list
   331→      handleRefreshFeatures();
   332→    } catch (error) {
   333→      const message = error instanceof Error ? error.message : String(error);
   334→      // Extract the actual error from "Harness command failed: Error: ..."
   335→      const match = message.match(/Error:\s*(.+)/);
   336→      throw new Error(match ? match[1] : message);
   337→    }
   338→  }, [activeProjectId, projects, handleRefreshFeatures]);
   339→
   340→  const handleDeleteTask = useCallback(async (taskId: string) => {
   341→    const activeProject = projects.find(p => p.id === activeProjectId);
   342→    if (!activeProject) return;
   343→
   344→    // Confirm before deleting
   345→    if (!window.confirm('Are you sure you want to delete this task?')) {
   346→      return;
   347→    }
   348→
   349→    await runHarnessCommand(activeProject.path, ['task', 'delete', taskId]);
   350→
   351→    // Refresh the task list
   352→    handleRefreshFeatures();
   353→  }, [activeProjectId, projects, handleRefreshFeatures]);
   354→
   355→  const handleMoveTask = useCallback(async (taskId: string, newStatus: string) => {
   356→    const activeProject = projects.find(p => p.id === activeProjectId);
   357→    if (!activeProject) return;
   358→
   359→    try {
   360→      await runHarnessCommand(activeProject.path, ['task', 'update', taskId, '--status', newStatus.toLowerCase()]);
   361→      // Refresh the task list
   362→      handleRefreshFeatures();
   363→    } catch (error) {
   364→      console.error('Failed to move task:', error);
   365→    }
   366→  }, [activeProjectId, projects, handleRefreshFeatures]);
   367→
   368→  // Play task - execute with Claude Code
   369→  const handlePlayTask = useCallback((task: Feature) => {
