   401→
   402→  // Calculate stats from actual features
   403→  const stats = {
   404→    completed: features.filter(f => f.status === 'done').length,
   405→    total: features.length,
   406→  };
   407→
   408→  const masthead = (
   409→    <Masthead>
   410→      <MastheadMain>
   411→        <MastheadBrand>
   412→          <Title headingLevel="h1" size="xl">HQ</Title>
   413→        </MastheadBrand>
   414→        <Label color="blue" isCompact>Harness Orchestrator</Label>
   415→        <Label
   416→          color={isConnected ? 'green' : 'red'}
   417→          isCompact
   418→          style={{ marginLeft: 8 }}
   419→        >
   420→          {isConnected ? 'Connected' : 'Disconnected'}
   421→        </Label>
   422→      </MastheadMain>
   423→    </Masthead>
