   477→              </EmptyStateActions>
   478→            </EmptyStateFooter>
   479→          </EmptyState>
   480→        </PageSection>
   481→      )}
   482→
   483→      {/* Project Content - only show when there's an active project */}
   484→      {activeProject && (
   485→        <>
   486→          <PageSection>
   487→            <Card>
   488→              <CardTitle>{activeProject.name}</CardTitle>
   489→              <CardBody>
   490→                <Content component="p">
   491→                  <strong>Path:</strong> {activeProject.path}
   492→                </Content>
   493→                <Content component="p">
   494→                  <strong>Tasks:</strong> {stats.completed}/{stats.total} complete
   495→                </Content>
   496→                <div style={{ marginTop: '16px', display: 'flex', gap: '8px' }}>
   497→                  <Button
   498→                    variant="secondary"
