   524→              <CardTitle>
   525→                Task Board
   526→                {isLoadingFeatures && <Spinner size="md" style={{ marginLeft: 8 }} />}
   527→              </CardTitle>
   528→              <CardBody>
   529→                <KanbanBoard
   530→                  features={features}
   531→                  onAddTask={handleOpenAddTask}
   532→                  onEditTask={handleOpenEditTask}
   533→                  onDeleteTask={handleDeleteTask}
   534→                  onMoveTask={handleMoveTask}
   535→                  onPlayTask={handlePlayTask}
   536→                />
   537→              </CardBody>
   538→            </Card>
   539→          </PageSection>
   540→
   541→          {/* Log Panel */}
   542→          <PageSection>
   543→            <Card>
   544→              <CardTitle>Process Logs</CardTitle>
   545→              <CardBody>
   546→                {logs.length > 0 ? (
