   577→
   578→      {/* Settings Dialog */}
   579→      <Settings
   580→        isOpen={isSettingsOpen}
   581→        onClose={() => setIsSettingsOpen(false)}
   582→        onSettingsChange={setSettings}
   583→      />
   584→
   585→      {/* Task Modal */}
   586→      <TaskModal
