     6→   ============================================================================= */
     7→
     8→:root {
     9→  font-family: ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont,
    10→               "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
    11→  /* Native macOS apps use 13-14px, not 16px web default */
