/* =============================================================================
   HQ - Native macOS Styling Foundation (F012 Phase 1)

   Goal: Make the app feel like a native macOS application, not a web app.
   Reference: Linear, Notion, Warp, Arc, Raycast
   ============================================================================= */

:root {
  font-family: ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont,
               "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
  /* Native macOS apps use 13-14px, not 16px web default */
  font-size: 14px;
  line-height: 1.5;

  /* Focus ring color - uses PatternFly variable if available */
  --focus-ring-color: var(--pf-t--global--color--brand--default, #0066cc);
}

/* =============================================================================
   Base Reset
   ============================================================================= */

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

/* =============================================================================
   User Selection - Native apps don't let you select UI chrome
   ============================================================================= */

/* Disable selection on all UI elements by default */
/* DISABLED FOR DEBUGGING - uncomment for production
body {
  user-select: none;
  -webkit-user-select: none;
}
*/

/* Allow selection only on actual content */
.selectable,
pre,
code,
.log-content,
[contenteditable="true"],
input,
textarea,
.pf-v6-c-log-viewer__text {
  user-select: text;
  -webkit-user-select: text;
}

/* =============================================================================
   Cursor - Native apps use default cursor, not pointer everywhere
   ============================================================================= */

body {
  cursor: default;
}

/* Only use pointer for actual links and interactive elements */
a[href],
button,
[role="button"],
[role="tab"],
[role="menuitem"],
[role="option"],
.clickable,
.pf-v6-c-button,
.pf-v6-c-tabs__link,
.pf-v6-c-menu__item {
  cursor: pointer;
}

/* Disabled elements */
[disabled],
[aria-disabled="true"],
.disabled {
  cursor: not-allowed;
}

/* Text inputs */
input,
textarea,
[contenteditable="true"] {
  cursor: text;
}

/* =============================================================================
   Focus States - Only show on keyboard navigation, not mouse clicks
   ============================================================================= */

/* Remove default focus outline */
*:focus {
  outline: none;
}

/* Show focus ring only on keyboard navigation (Tab key) */
*:focus-visible {
  outline: 2px solid var(--focus-ring-color);
  outline-offset: 2px;
}

/* Ensure buttons and links show focus-visible */
button:focus-visible,
a:focus-visible,
[role="button"]:focus-visible,
[role="tab"]:focus-visible,
.pf-v6-c-button:focus-visible {
  outline: 2px solid var(--focus-ring-color);
  outline-offset: 2px;
}

/* =============================================================================
   Drag Prevention - Disable image/element dragging
   ============================================================================= */

img,
svg,
[draggable="false"] {
  -webkit-user-drag: none;
  user-drag: none;
}

/* Allow explicit draggable elements */
[draggable="true"] {
  -webkit-user-drag: element;
}

/* =============================================================================
   Scroll Behavior - No bounce/overscroll
   ============================================================================= */

html,
body {
  overscroll-behavior: none;
}

/* Smooth scrolling for containers */
.scroll-smooth {
  scroll-behavior: smooth;
}

/* =============================================================================
   Window Background - Transparent for vibrancy support
   ============================================================================= */

html,
body {
  background: transparent;
  min-height: 100vh;
}

/* Fallback background color when vibrancy is not available */
body {
  background-color: var(--pf-t--global--background--color--primary--default, #f0f0f0);
}

/* Dark mode support */
@media (prefers-color-scheme: dark) {
  body {
    background-color: var(--pf-t--global--background--color--primary--default, #1a1a1a);
  }
}

/* =============================================================================
   Titlebar Drag Region - Allow dragging from header area
   ============================================================================= */

.titlebar,
.titlebar-drag,
[data-tauri-drag-region] {
  -webkit-app-region: drag;
}

/* Interactive elements within titlebar should not drag */
.titlebar button,
.titlebar a,
.titlebar input,
.titlebar [role="button"],
.titlebar-no-drag,
[data-tauri-drag-region] button,
[data-tauri-drag-region] a,
[data-tauri-drag-region] input {
  -webkit-app-region: no-drag;
}

/* =============================================================================
   Root Container
   ============================================================================= */

#root {
  min-height: 100vh;
}

/* =============================================================================
   Context Menu Styling (Notion/Linear style)
   ============================================================================= */

.context-menu {
  user-select: none;
  -webkit-user-select: none;
}

/* =============================================================================
   Utility Classes
   ============================================================================= */

/* Make text selectable */
.text-selectable {
  user-select: text;
  -webkit-user-select: text;
}

/* Make element draggable */
.draggable {
  -webkit-user-drag: element;
  cursor: grab;
}

.draggable:active {
  cursor: grabbing;
}

/* Prevent any interaction */
.no-interaction {
  pointer-events: none;
  user-select: none;
}

/* =============================================================================
   Window Focus/Blur State (F012 Phase 7)

   Native macOS apps dim their UI when the window loses focus.
   This provides visual feedback about which window is active.
   ============================================================================= */

/* Window unfocused state - subtle dim effect */
.window-unfocused {
  --window-opacity: 0.85;
}

/* Dim selection highlights when unfocused (like native macOS) */
.window-unfocused .tab-active,
.window-unfocused [aria-selected="true"],
.window-unfocused .pf-m-selected,
.window-unfocused .pf-v6-c-tabs__link::after {
  background-color: var(--pf-t--global--background--color--secondary--default, #d2d2d2) !important;
}

/* Reduce vibrancy of cards/panels when unfocused */
.window-unfocused .pf-v6-c-card,
.window-unfocused .pf-v6-c-panel,
.window-unfocused .kanban-card {
  opacity: var(--window-opacity, 0.85);
  transition: opacity 0.2s ease-out;
}

/* Dim primary buttons when unfocused */
.window-unfocused .pf-v6-c-button.pf-m-primary {
  opacity: var(--window-opacity, 0.85);
}

/* Keep important interactive elements fully visible */
.window-unfocused .keep-visible,
.window-unfocused input:focus,
.window-unfocused textarea:focus,
.window-unfocused [contenteditable="true"]:focus {
  opacity: 1;
}

/* Subtle transition when regaining focus */
html:not(.window-unfocused) .pf-v6-c-card,
html:not(.window-unfocused) .pf-v6-c-panel,
html:not(.window-unfocused) .kanban-card {
  transition: opacity 0.15s ease-in;
}

