     4→ * Replaces Tauri backend with pure Node.js/Bun implementation.
     5→ * Provides:
     6→ * - PTY support via node-pty
     7→ * - WebSocket for real-time communication
     8→ * - REST API for harness CLI commands
     9→ * - File system watching
    10→ */
    11→
    12→import { spawn, type Subprocess } from "bun";
    13→import { watch, type FSWatcher } from "fs";
    14→import { readFile, writeFile, mkdir, access, stat } from "fs/promises";
    15→import { join, basename } from "path";
    16→import { randomBytes } from "crypto";
    17→import { homedir } from "os";
    18→
    19→// Expand ~ to home directory
    20→function expandPath(path: string): string {
    21→  if (path.startsWith("~")) {
    22→    return join(homedir(), path.slice(1));
    23→  }
    24→  return path;
    25→}
    26→
    27→// Types
    28→interface ProcessInfo {
    29→  id: string;
    30→  cmd: string;
    31→  args: string[];
    32→  cwd: string;
    33→  rows: number;
    34→  cols: number;
    35→  running: boolean;
    36→  createdAt: number;
    37→}
    38→
    39→interface PtyProcess {
    40→  info: ProcessInfo;
    41→  process: Subprocess;
    42→}
    43→
    44→interface RpcRequest {
    45→  id: string;
    46→  cmd: string;
    47→  args: Record<string, unknown>;
    48→}
    49→
    50→interface RpcResponse {
    51→  id: string;
    52→  success: boolean;
    53→  result?: unknown;
    54→  error?: string;
    55→}
    56→
    57→interface RpcEvent {
    58→  event: string;
    59→  payload: unknown;
    60→}
    61→
    62→interface WatcherEntry {
    63→  watcher: FSWatcher;
    64→  projectPath: string;
    65→}
    66→
    67→// Global state
    68→const processes = new Map<string, PtyProcess>();
    69→const watchers = new Map<string, WatcherEntry>();
    70→const wsClients = new Set<{ send: (data: string) => void; readyState: number }>();
    71→
    72→// Generate unique ID
    73→function generateId(): string {
    74→  return randomBytes(16).toString("hex");
    75→}
    76→
    77→// Broadcast event to all WebSocket clients
    78→function broadcast(event: RpcEvent): void {
    79→  const data = JSON.stringify(event);
    80→  for (const client of wsClients) {
    81→    if (client.readyState === 1) {
    82→      try {
    83→        client.send(data);
    84→      } catch (e) {
    85→        console.error("[WS] Failed to send:", e);
    86→      }
    87→    }
    88→  }
    89→}
    90→
    91→// PTY Commands
    92→async function ptySpawn(
    93→  cmd: string,
    94→  args: string[] = [],
    95→  cwd: string = process.cwd(),
    96→  rows: number = 24,
    97→  cols: number = 80
    98→): Promise<ProcessInfo> {
    99→  const id = generateId();
   100→
   101→  // Expand ~ and resolve cwd
   102→  const resolvedCwd = expandPath(cwd);
   103→
   104→  // Use Bun's spawn with PTY-like behavior
   105→  const proc = spawn({
   106→    cmd: [cmd, ...args],
   107→    cwd: resolvedCwd,
   108→    env: {
   109→      ...process.env,
   110→      TERM: "xterm-256color",
   111→      COLUMNS: String(cols),
   112→      LINES: String(rows),
   113→    },
   114→    stdin: "pipe",
   115→    stdout: "pipe",
   116→    stderr: "pipe",
   117→  });
   118→
   119→  const info: ProcessInfo = {
   120→    id,
   121→    cmd,
   122→    args,
   123→    cwd: resolvedCwd,
   124→    rows,
   125→    cols,
   126→    running: true,
   127→    createdAt: Date.now(),
   128→  };
   129→
   130→  processes.set(id, {
   131→    info,
   132→    process: proc,
   133→  });
   134→
   135→  // Stream stdout
   136→  (async () => {
   137→    const reader = proc.stdout.getReader();
   138→    try {
   139→      while (true) {
   140→        const { done, value } = await reader.read();
   141→        if (done) break;
   142→        const text = new TextDecoder().decode(value);
   143→        broadcast({
   144→          event: "pty-output",
   145→          payload: { id, data: text },
   146→        });
   147→      }
   148→    } catch (e) {
   149→      console.error(`[PTY ${id}] stdout error:`, e);
   150→    }
   151→  })();
   152→
   153→  // Stream stderr
   154→  (async () => {
   155→    const reader = proc.stderr.getReader();
   156→    try {
   157→      while (true) {
   158→        const { done, value } = await reader.read();
   159→        if (done) break;
   160→        const text = new TextDecoder().decode(value);
   161→        broadcast({
   162→          event: "pty-output",
   163→          payload: { id, data: text },
   164→        });
   165→      }
   166→    } catch (e) {
   167→      console.error(`[PTY ${id}] stderr error:`, e);
   168→    }
   169→  })();
   170→
   171→  // Handle exit
   172→  proc.exited.then((code) => {
   173→    const entry = processes.get(id);
   174→    if (entry) {
   175→      entry.info.running = false;
   176→    }
   177→    broadcast({
   178→      event: "pty-exit",
   179→      payload: { id, code },
   180→    });
   181→    console.log(`[PTY ${id}] Process exited with code: ${code}`);
   182→  });
   183→
   184→  console.log(`[PTY ${id}] Spawned: ${cmd} ${args.join(" ")}`);
   185→  return info;
   186→}
   187→
   188→async function ptyWrite(id: string, data: string): Promise<void> {
   189→  const entry = processes.get(id);
   190→  if (!entry) {
   191→    throw new Error(`Process not found: ${id}`);
   192→  }
   193→  if (!entry.info.running) {
   194→    throw new Error(`Process not running: ${id}`);
   195→  }
   196→
   197→  // Bun's stdin is a FileSink with a write() method
   198→  const stdin = entry.process.stdin;
   199→  if (stdin && typeof stdin.write === "function") {
   200→    stdin.write(data);
   201→    stdin.flush();
   202→  } else {
   203→    throw new Error("stdin not available or not writable");
   204→  }
   205→}
   206→
   207→async function ptyKill(id: string): Promise<void> {
   208→  const entry = processes.get(id);
   209→  if (!entry) {
   210→    throw new Error(`Process not found: ${id}`);
   211→  }
   212→
   213→  entry.process.kill();
   214→  entry.info.running = false;
   215→  console.log(`[PTY ${id}] Killed`);
   216→}
   217→
   218→function ptyList(): ProcessInfo[] {
   219→  return Array.from(processes.values()).map((e) => e.info);
   220→}
   221→
   222→function ptyGet(id: string): ProcessInfo | null {
   223→  return processes.get(id)?.info || null;
   224→}
   225→
   226→// Harness CLI wrapper
   227→async function runHarnessCommand(
   228→  projectPath: string,
   229→  args: string[]
   230→): Promise<string> {
   231→  // Find harness binary - check common locations
   232→  const possiblePaths = [
   233→    join(process.cwd(), "target", "release", "harness"),
   234→    join(process.cwd(), "target", "debug", "harness"),
   235→    join(process.cwd(), "src-tauri", "target", "release", "harness"),
   236→    join(process.cwd(), "src-tauri", "target", "debug", "harness"),
   237→    "harness", // In PATH
   238→  ];
   239→
   240→  let harnessPath = "harness";
   241→  for (const p of possiblePaths) {
   242→    try {
   243→      await access(p);
   244→      harnessPath = p;
   245→      break;
   246→    } catch {
   247→      // Try next
   248→    }
   249→  }
   250→
   251→  console.log(`[Harness] Running: ${harnessPath} ${args.join(" ")} in ${projectPath}`);
   252→
   253→  const proc = spawn({
   254→    cmd: [harnessPath, ...args],
   255→    cwd: projectPath,
   256→    stdout: "pipe",
   257→    stderr: "pipe",
   258→  });
   259→
   260→  const stdout = await new Response(proc.stdout).text();
   261→  const stderr = await new Response(proc.stderr).text();
   262→  const exitCode = await proc.exited;
   263→
   264→  if (exitCode !== 0) {
   265→    throw new Error(`Harness command failed (exit ${exitCode}): ${stderr || stdout}`);
   266→  }
   267→
   268→  return stdout;
   269→}
   270→
   271→// File watcher commands
   272→async function watcherStart(projectPath: string): Promise<boolean> {
   273→  if (watchers.has(projectPath)) {
   274→    return true; // Already watching
   275→  }
   276→
   277→  const harnessDir = join(projectPath, ".harness");
   278→
   279→  try {
   280→    await access(harnessDir);
   281→  } catch {
   282→    console.log(`[Watcher] .harness dir not found: ${harnessDir}`);
   283→    return false;
   284→  }
   285→
   286→  const watcher = watch(harnessDir, { recursive: true }, (eventType, filename) => {
   287→    if (!filename) return;
   288→
   289→    let changeType: "db" | "config" | "unknown" = "unknown";
   290→    if (filename.endsWith(".db") || filename.endsWith(".db-wal") || filename.endsWith(".db-shm")) {
   291→      changeType = "db";
   292→    } else if (filename.endsWith(".json")) {
   293→      changeType = "config";
   294→    }
   295→
   296→    broadcast({
   297→      event: "harness-change",
   298→      payload: {
   299→        project_path: projectPath,
   300→        change_type: changeType,
   301→        file: filename,
   302→      },
   303→    });
   304→  });
   305→
   306→  watchers.set(projectPath, { watcher, projectPath });
   307→  console.log(`[Watcher] Started watching: ${harnessDir}`);
   308→  return true;
   309→}
   310→
   311→function watcherStop(projectPath: string): boolean {
   312→  const entry = watchers.get(projectPath);
   313→  if (!entry) return false;
   314→
   315→  entry.watcher.close();
   316→  watchers.delete(projectPath);
   317→  console.log(`[Watcher] Stopped watching: ${projectPath}`);
   318→  return true;
   319→}
   320→
   321→function watcherList(): string[] {
   322→  return Array.from(watchers.keys());
   323→}
   324→
   325→// Check if path has .harness folder
   326→async function checkHarnessExists(path: string): Promise<boolean> {
   327→  try {
   328→    const harnessPath = join(path, ".harness");
   329→    await access(harnessPath);
   330→    return true;
   331→  } catch {
   332→    return false;
   333→  }
   334→}
   335→
   336→// Get project info from package.json
   337→async function getProjectInfo(path: string): Promise<{ name: string; version?: string } | null> {
   338→  try {
   339→    const pkgPath = join(path, "package.json");
   340→    const content = await readFile(pkgPath, "utf-8");
   341→    const pkg = JSON.parse(content);
   342→    return {
   343→      name: pkg.name || basename(path),
   344→      version: pkg.version,
   345→    };
   346→  } catch {
   347→    return {
   348→      name: basename(path),
   349→    };
   350→  }
   351→}
   352→
   353→// Get git info
   354→async function getGitInfo(path: string): Promise<{ hash: string; message: string; author: string; date: string } | null> {
   355→  try {
   356→    const proc = spawn({
   357→      cmd: ["git", "log", "-1", "--format=%H%n%s%n%an%n%aI"],
   358→      cwd: path,
   359→      stdout: "pipe",
   360→      stderr: "pipe",
   361→    });
   362→
   363→    const stdout = await new Response(proc.stdout).text();
   364→    const exitCode = await proc.exited;
   365→
   366→    if (exitCode !== 0) return null;
   367→
   368→    const lines = stdout.trim().split("\n");
   369→    if (lines.length < 4) return null;
   370→
   371→    return {
   372→      hash: lines[0],
   373→      message: lines[1],
   374→      author: lines[2],
   375→      date: lines[3],
   376→    };
   377→  } catch {
   378→    return null;
   379→  }
   380→}
   381→
   382→// Handle RPC request
   383→async function handleRpcRequest(request: RpcRequest): Promise<RpcResponse> {
   384→  const { id, cmd, args } = request;
   385→
   386→  try {
   387→    let result: unknown;
   388→
   389→    switch (cmd) {
   390→      case "pty_spawn":
   391→        result = await ptySpawn(
   392→          args.cmd as string,
   393→          args.args as string[],
   394→          args.cwd as string,
   395→          args.rows as number,
   396→          args.cols as number
   397→        );
   398→        break;
   399→
   400→      case "pty_write":
   401→        await ptyWrite(args.id as string, args.data as string);
   402→        result = null;
   403→        break;
   404→
   405→      case "pty_resize":
   406→        // Not fully supported with Bun spawn, but we can store the values
   407→        const entry = processes.get(args.id as string);
   408→        if (entry) {
   409→          entry.info.rows = args.rows as number;
   410→          entry.info.cols = args.cols as number;
   411→        }
   412→        result = null;
   413→        break;
   414→
   415→      case "pty_kill":
   416→        await ptyKill(args.id as string);
   417→        result = null;
   418→        break;
   419→
   420→      case "pty_list":
   421→        result = ptyList();
   422→        break;
   423→
   424→      case "pty_get":
   425→        result = ptyGet(args.id as string);
   426→        break;
   427→
   428→      case "run_harness_command":
   429→        result = await runHarnessCommand(
   430→          args.projectPath as string,
   431→          args.args as string[]
   432→        );
   433→        break;
   434→
   435→      case "harness_watch_start":
   436→        result = await watcherStart(args.projectPath as string);
   437→        break;
   438→
   439→      case "harness_watch_stop":
   440→        result = watcherStop(args.projectPath as string);
   441→        break;
   442→
   443→      case "harness_watch_list":
   444→        result = watcherList();
   445→        break;
   446→
   447→      case "check_harness_exists":
   448→        result = await checkHarnessExists(args.path as string);
   449→        break;
   450→
   451→      case "get_project_info":
   452→        result = await getProjectInfo(args.path as string);
   453→        break;
   454→
   455→      case "get_git_info":
   456→        result = await getGitInfo(args.path as string);
   457→        break;
   458→
   459→      case "get_home_dir":
   460→        result = homedir();
   461→        break;
   462→
   463→      case "check_path_exists":
   464→        try {
   465→          await access(args.path as string);
   466→          result = true;
   467→        } catch {
   468→          result = false;
   469→        }
   470→        break;
   471→
   472→      default:
   473→        throw new Error(`Unknown command: ${cmd}`);
   474→    }
   475→
   476→    return { id, success: true, result };
   477→  } catch (error) {
   478→    const message = error instanceof Error ? error.message : String(error);
   479→    console.error(`[RPC] Error in ${cmd}:`, message);
   480→    return { id, success: false, error: message };
   481→  }
   482→}
   483→
   484→// Create HTTP server with WebSocket support
   485→const PORT = parseInt(process.env.PORT || "9876");
   486→
   487→console.log(`
   488→╔══════════════════════════════════════════════════════════════╗
   489→║  HQ Web Backend Server                                       ║
   490→╠══════════════════════════════════════════════════════════════╣
   491→║  Port: ${PORT}                                                 ║
   492→║  WebSocket: ws://localhost:${PORT}/ws                          ║
   493→║  Health: http://localhost:${PORT}/health                       ║
   494→╚══════════════════════════════════════════════════════════════╝
   495→`);
   496→
   497→const server = Bun.serve({
   498→  port: PORT,
   499→
   500→  async fetch(req, server) {
   501→    const url = new URL(req.url);
   502→
   503→    // CORS headers
   504→    const corsHeaders = {
   505→      "Access-Control-Allow-Origin": "*",
   506→      "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
   507→      "Access-Control-Allow-Headers": "Content-Type",
   508→    };
   509→
   510→    // Handle CORS preflight
   511→    if (req.method === "OPTIONS") {
   512→      return new Response(null, { headers: corsHeaders });
   513→    }
   514→
   515→    // Health check
   516→    if (url.pathname === "/health") {
   517→      return Response.json(
   518→        { status: "ok", processes: processes.size, watchers: watchers.size },
   519→        { headers: corsHeaders }
   520→      );
   521→    }
   522→
   523→    // WebSocket upgrade
   524→    if (url.pathname === "/ws") {
   525→      const upgraded = server.upgrade(req);
   526→      if (!upgraded) {
   527→        return new Response("WebSocket upgrade failed", { status: 400 });
   528→      }
   529→      return undefined;
   530→    }
   531→
   532→    // REST API for RPC (alternative to WebSocket)
   533→    if (url.pathname === "/rpc" && req.method === "POST") {
   534→      try {
   535→        const request = await req.json() as RpcRequest;
   536→        const response = await handleRpcRequest(request);
   537→        return Response.json(response, { headers: corsHeaders });
   538→      } catch (e) {
   539→        return Response.json(
   540→          { id: "error", success: false, error: String(e) },
   541→          { status: 400, headers: corsHeaders }
   542→        );
   543→      }
   544→    }
   545→
   546→    // Serve static files (if needed for production)
   547→    if (url.pathname === "/" || url.pathname === "/index.html") {
   548→      return new Response("HQ Web Backend Server is running. Connect via WebSocket at /ws", {
   549→        headers: { "Content-Type": "text/plain", ...corsHeaders },
   550→      });
   551→    }
   552→
   553→    return new Response("Not found", { status: 404, headers: corsHeaders });
   554→  },
   555→
   556→  websocket: {
   557→    open(ws) {
   558→      wsClients.add(ws as any);
   559→      console.log(`[WS] Client connected. Total: ${wsClients.size}`);
   560→    },
   561→
   562→    close(ws) {
   563→      wsClients.delete(ws as any);
   564→      console.log(`[WS] Client disconnected. Total: ${wsClients.size}`);
   565→    },
   566→
   567→    async message(ws, message) {
   568→      try {
   569→        const request = JSON.parse(message as string) as RpcRequest;
   570→        const response = await handleRpcRequest(request);
   571→
   572→        // Send response as RPC event
   573→        ws.send(
   574→          JSON.stringify({
   575→            event: "rpc-response",
   576→            payload: response,
   577→          })
   578→        );
   579→      } catch (e) {
   580→        ws.send(
   581→          JSON.stringify({
   582→            event: "rpc-response",
   583→            payload: {
   584→              id: "error",
   585→              success: false,
   586→              error: String(e),
   587→            },
   588→          })
   589→        );
   590→      }
   591→    },
   592→  },
   593→});
   594→
   595→console.log(`Server running at http://localhost:${PORT}`);
   596→
   597→// Graceful shutdown
   598→process.on("SIGINT", () => {
   599→  console.log("\n[Server] Shutting down...");
   600→
   601→  // Kill all processes
   602→  for (const [id, entry] of processes) {
   603→    try {
   604→      entry.process.kill();
   605→      console.log(`[PTY ${id}] Killed on shutdown`);
   606→    } catch {
   607→      // Ignore
   608→    }
   609→  }
   610→
   611→  // Close all watchers
   612→  for (const [path, entry] of watchers) {
   613→    entry.watcher.close();
   614→    console.log(`[Watcher] Stopped: ${path}`);
   615→  }
   616→
   617→  process.exit(0);
   618→});
   619→

