} from '../lib/rpc';

// Re-export the type from rpc
export type { HQSettings } from '../lib/rpc';

const DEFAULT_SETTINGS: HQSettings = {
  theme: 'dark',
  logBufferSize: 10000,
  defaultShell: '/bin/zsh',
  ptyRows: 24,
  ptyCols: 80,
  autoScrollLogs: true,
  showTimestamps: true,
};

interface SettingsProps {
  isOpen: boolean;
  onClose: () => void;
  onSettingsChange?: (settings: HQSettings) => void;
}

export function Settings({
  isOpen,
  onClose,
  onSettingsChange,
}: SettingsProps): React.JSX.Element {
  const [settings, setSettings] = useState<HQSettings>(DEFAULT_SETTINGS);
  const [isDirty, setIsDirty] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  // Load settings from backend on open
  useEffect(() => {
    if (isOpen) {
      setIsLoading(true);
      rpcGetSettings()
        .then(setSettings)
        .catch((e) => console.error('Failed to load settings:', e))
        .finally(() => setIsLoading(false));
    }
  }, [isOpen]);

  const updateSetting = useCallback(
    <K extends keyof HQSettings>(key: K, value: HQSettings[K]) => {
      setSettings((prev) => {
        const updated = { ...prev, [key]: value };
        return updated;
      });
      setIsDirty(true);
    },
    []
  );

  const handleSave = useCallback(async () => {
    try {
      const saved = await rpcSetSettings(settings);
      setIsDirty(false);
      onSettingsChange?.(saved);
      onClose();
    } catch (e) {
      console.error('Failed to save settings:', e);
    }
  }, [settings, onSettingsChange, onClose]);

  const handleReset = useCallback(() => {
    setSettings(DEFAULT_SETTINGS);
    setIsDirty(true);
  }, []);

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      variant={ModalVariant.medium}
      aria-label="Settings"
    >
      <ModalHeader title="Settings" />
      <ModalBody>
        <motion.div
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.2 }}
        >
          <Form>
            {/* Appearance Section */}
